import csv
import json
import os
import re
from collections import defaultdict, deque

# 1. Load Sales and find exact consumption quantities per day
# We just need to know how many units of each product each store SOLD on each day.
sold_per_day = defaultdict(lambda: defaultdict(lambda: defaultdict(int)))
with open('/app/sales_log.csv', 'r') as f:
    for row in csv.DictReader(f):
        p = row['Product_ID']
        s = row['Store_ID']
        d = int(row['Day'])
        sold_per_day[d][s][p] += int(row['Sold_Quantity'])

# 2. Parsers
def parse_supplier_receipt(path):
    # returns dict: product -> qty
    res = {}
    with open(path, 'r') as f:
        content = f.read().strip()
        if not content: return res
        if path.endswith('.json'):
            data = json.loads(content)
            for item in data.get('items', []):
                res[item['prod_id']] = int(item['delivered_qty'])
        elif path.endswith('.csv'):
            lines = content.split('\n')[1:]
            for line in lines:
                if not line.strip(): continue
                p, q = line.split(';')
                res[p] = int(q)
        elif path.endswith('key-value.txt'):
            for line in content.split('\n'):
                if 'DELIVERED_QTY' in line:
                    p = re.search(r'PRODUCT:\s*(P_\d+)', line).group(1)
                    q = int(re.search(r'DELIVERED_QTY:\s*(\d+)', line).group(1))
                    res[p] = q
        elif path.endswith('text-template.txt'):
            for line in content.split('\n'):
                if 'delivered' in line:
                    m = re.search(r'delivered (\d+) units of product (P_\d+)', line)
                    if m:
                        res[m.group(2)] = int(m.group(1))
    return res

def parse_store_order(path):
    res = {}
    with open(path, 'r') as f:
        content = f.read().strip()
        if not content: return res
        if path.endswith('.json'):
            data = json.loads(content)
            for item in data.get('items', []):
                res[item['prod_id']] = int(item['qty'])
        elif path.endswith('.csv'):
            lines = content.split('\n')[1:]
            for line in lines:
                if not line.strip(): continue
                p, q = line.split(';')
                res[p] = int(q)
        elif path.endswith('key-value.txt'):
            for line in content.split('\n'):
                if 'ORDER_QTY' in line:
                    p = re.search(r'ORDER_PRODUCT:\s*(P_\d+)', line).group(1)
                    q = int(re.search(r'ORDER_QTY:\s*(\d+)', line).group(1))
                    res[p] = q
        elif path.endswith('text-template.txt'):
            for line in content.split('\n'):
                if 'deliver' in line:
                    m = re.search(r'deliver (\d+) units of product (P_\d+)', line)
                    if m:
                        res[m.group(2)] = int(m.group(1))
    return res

# 3. Simulate
wholesaler_inv = defaultdict(deque) # P -> deque of (producer, qty)
store_inv = defaultdict(lambda: defaultdict(deque)) # S -> P -> deque of (producer, qty)

consumed_batches = defaultdict(lambda: defaultdict(lambda: defaultdict(set))) # P -> S -> D -> set of producers

for day in range(1, 366):
    # a. Wholesaler receives from suppliers
    # Find sequence
    sup_seq = []
    prefix = f"/app/raw_wholesaler_receipts/day_{day:03d}_"
    for fname in os.listdir("/app/raw_wholesaler_receipts"):
        if fname.startswith(f"day_{day:03d}_"):
            # read sequence
            with open(os.path.join("/app/raw_wholesaler_receipts", fname), 'r') as f:
                content = f.read()
                seq = int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content).group(1))
                sup = re.search(r'SUPPLIER_ID:\s*(PR_\d+)', content).group(1)
                sup_seq.append((seq, sup))
    sup_seq.sort()

    for _, sup in sup_seq:
        # find supplier receipt
        receipt_path = None
        for fname in os.listdir("/app/raw_supplier_receipts"):
            if fname.startswith(f"day_{day:03d}_{sup}_") and not fname.endswith('receipt.txt'):
                receipt_path = os.path.join("/app/raw_supplier_receipts", fname)
                break
        if receipt_path:
            delivered = parse_supplier_receipt(receipt_path)
            for p, q in delivered.items():
                if q > 0:
                    wholesaler_inv[p].append([sup, q])

    # b. Stores order from wholesaler
    store_seq = []
    for fname in os.listdir("/app/raw_wholesaler_store_receipts"):
        if fname.startswith(f"day_{day:03d}_"):
            with open(os.path.join("/app/raw_wholesaler_store_receipts", fname), 'r') as f:
                content = f.read()
                seq = int(re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', content).group(1))
                store = re.search(r'STORE_ID:\s*(S_\d+)', content).group(1)
                store_seq.append((seq, store))
    store_seq.sort()

    for _, store in store_seq:
        order_path = None
        for fname in os.listdir("/app/raw_orders"):
            if fname.startswith(f"day_{day:03d}_{store}_") and not fname.endswith('receipt.txt'):
                order_path = os.path.join("/app/raw_orders", fname)
                break
        if order_path:
            ordered = parse_store_order(order_path)
            for p, q in ordered.items():
                fulfill = q
                while fulfill > 0 and wholesaler_inv[p]:
                    sup, avail = wholesaler_inv[p][0]
                    if avail <= fulfill:
                        store_inv[store][p].append([sup, avail])
                        fulfill -= avail
                        wholesaler_inv[p].popleft()
                    else:
                        store_inv[store][p].append([sup, fulfill])
                        wholesaler_inv[p][0][1] -= fulfill
                        fulfill = 0

    # c. Stores sell to consumers
    for store, p_dict in sold_per_day[day].items():
        for p, sold in p_dict.items():
            while sold > 0 and store_inv[store][p]:
                sup, avail = store_inv[store][p][0]
                consumed_batches[p][store][day].add(sup)
                if avail <= sold:
                    sold -= avail
                    store_inv[store][p].popleft()
                else:
                    store_inv[store][p][0][1] -= sold
                    sold = 0
            if sold > 0:
                print(f"Warning: Store {store} sold {sold} more {p} than it had on Day {day}")

# Save consumed batches to a JSON file
out = {}
for p in consumed_batches:
    out[p] = {}
    for s in consumed_batches[p]:
        out[p][s] = {}
        for d in consumed_batches[p][s]:
            out[p][s][d] = list(consumed_batches[p][s][d])

with open('/app/consumed.json', 'w') as f:
    json.dump(out, f)
print("Simulation complete.")
EOF
